insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (210511, 10, 'ChenEylon', 'Using reverse chronology to put the audience in the shoes of a guy with short-term memory loss is brilliant. It''s a perfect puzzle.', null); -- 210511 Memento (2000)
