insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (46878, 7, 'Lior', 'The awkward situations and Bridget’s romantic struggles are relatable, even if it is not as strong as the first movie.', null);  -- Bridget Jones: The Edge of Reason 2004
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (66194, 9, 'Lior', 'The light romantic storyline and Cher’s character make it fun, easy to watch, and very memorable.', null);  -- Clueless 1995
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (59578, 9, 'Lior', 'The magical world and Charlie’s relationship with his family make it emotional and enjoyable.', null);  -- Charlie and the Chocolate Factory 2005
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (139657, 8, 'Lior', 'The introduction to the magical world and the friendships make it very engaging and nostalgic.', null);  -- Harry Potter and the Sorcerer''s Stne 2001
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (139650, 8, 'Lior', 'The stronger mystery and darker tone make it more interesting while still keeping the emotional connections.', null);  -- Harry Potter and the Chamber of Secrets 2002
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (139655, 9, 'Lior', 'The time-travel element and deeper character development make it one of the most engaging in the series.', null);  -- Harry Potter and the Prisoner of Azkaban 2004
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (139652, 8, 'Lior', 'The emotional stakes and relationships become stronger, even though it is more intense.', null);  -- Harry Potter and the Goblet of Fire 2005
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (30959, 4, 'Lior', 'The darker superhero tone and focus on action make it less appealing to me compared to emotional stories.', null);  -- Batman Begins 2005
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (30955, 4, 'Lior', 'The visual style is strong, but the superhero focus and lack of emotional connection make it less engaging for me.', null);  -- Batman 1989
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (30967, 4, 'Lior', 'Even with memorable characters, the dark and action-heavy tone is not really my style.', null);  -- Batman Returns 1992
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (25192, 7, 'Lior', 'The personal struggles and ambition make it interesting, though it feels more serious than emotional.', null);  -- The Aviator 2004
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (56871, 10, 'Lior', 'The cat-and-mouse dynamic and the charm of the main character make it very fun and engaging.', null);  -- Catch Me If You Can 2002
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (34077, 10, 'Lior', 'This is one of my all time favorites! The unique life story and the emotional relationship make it very touching and memorable.', null);  -- The Curious Case of Benjamn Button
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (129185, 7, 'Lior', 'The emotional motivation of Maximus makes the story stronger.', null);  -- Gladiator 2000
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (312150, 10, 'Lior', 'I really enjoy Spy Kids because it is imaginative, family-friendly, and adventurous without feeling too heavy or violent.', null);  # 312150 Spy Kids 2001
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (199763, 6, 'Lior', 'It is interesting to see Madonna’s music videos, but it feels more like a collection than a story.', null);  # Madonna: The Immaculate Collection 1990
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (199764, 6, 'Lior', 'The different eras of Madonna’s style are interesting, but it is less engaging than a narrative film.', null);  # Madonna: The Video Collection 93:99 1999
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (192514, 5, 'Lior', 'The spy theme and action scenes are not really my preference compared to romantic or emotional films.', null);  # Live and Let Die 1973
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (194492, 6, 'Lior', 'The fantasy world and characters are interesting.', null);  # Lord of the Rings 1990
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (190677, 6, 'Lior', 'The story about relationships and identity is interesting, but it is not very memorable.', null);  # Like a Lady 1996
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (192850, 6, 'Lior', 'The coming-of-age elements are relatable, but the story feels quite simple.', null);  # Lizzie 2001
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (194313, 6, 'Lior', 'The character-focused story is interesting, but it feels less emotional than I usually prefer.', null);  # Looking Out 2002
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (215875, 3, 'Lior', 'I am less connected to action and spy movies, and this kind of fast-paced mission plot is not usually my favorite.', null);  # 215875 Mission: Impossible 1991
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (220276, 9, 'Lior', 'I loved the music, the romance, and the dramatic atmosphere, and the film feels very emotional.', null);  # 220276 Moulin Rouge! 2001
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (220805, 9, 'Lior', 'The chemistry between the leads is entertaining, I love Brad Pitt and Angelina Jolie', null);  # 220805 Mr. and Mrs. Smith 2005
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (263360, 10, 'Lior', 'I love this movie! iconic scenes and the best actors- Richard Gere and Julia Roberts, the story is charming', null);  # 263360 Pretty Woman 1990
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (290070, 9, 'Lior', 'This is a deeply powerful and emotional historical film, and I appreciated how meaningful and unforgettable the story is.', null);  # 290070 Schindler's List 1993
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (300229, 10, 'Lior', 'I love the humor, the lovable characters, and the way the movie works as both a funny children''s film and a clever story for adults.', null);  # 300229 Shrek 2001
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (300230, 9, 'Lior', 'A very fun sequel with great humor, memorable side characters, and an entertaining fairy-tale world. I also like the music', null);  # 300230 Shrek 2 2004
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (300233, 7, 'Lior', 'I like the Shrek world and the characters, so this is still enjoyable, even though it feels smaller than the main films.', null);  # 300233 Shrek 4-D 2003
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (311036, 4, 'Lior', 'Superhero action movies are usually not my favorite, and although Spider-Man is iconic, this genre is less enjoyable for me.', null);  # 311036 Spider-Man 2000
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (311604, 8, 'Lior', 'I enjoy SpongeBob because it is silly, colorful, and fun, and reminds me of my childhood', null);  # 311604 SpongeBob SquarePants: Legend of the Lost Spatula 2001
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (311606, 8, 'Lior', 'This is fun and light, and I like the humorous SpongeBob style and the familiar characters.', null);  # 311606 SpongeBob SquarePants: Revenge of the Flying Dutchman 2002
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (311607, 8, 'Lior', 'I like the playful humor and the cheerful atmosphere, and SpongeBob is always entertaining in a simple and nostalgic way.', null);  # 311607 SpongeBob SquarePants: SuperSponge 2001
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (312151, 9, 'Lior', 'A very fun sequel with creative settings and a playful adventure style that makes it enjoyable as a family movie.', null);  # 312151 Spy Kids 2: Island of Lost Dreams 2002
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (312152, 8, 'Lior', 'Still entertaining and imaginative', null);  # 312152 Spy Kids 3-D: Game Over 2003
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (313464, 2, 'Lior', 'This is exactly the kind of action-driven science fiction title I usually do not connect with very much.', null);  # 313464 Star Wars Rogue Leader: Rogue Squadron 2 2001
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (319602, 4, 'Lior', 'I understand why this is a classic superhero movie, but superhero and action films are generally not my personal preference.', null);  # 319602 Superman 1978
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (319613, 3, 'Lior', 'Like other superhero sequels, this is less aligned with my taste, I find it boring', null);  # 319613 Superman II 1980
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (333856, 10, 'Lior', 'I love the romance, the emotional story, and the tragic scale of the film, and it is one of the most memorable love stories, also amazing music', null);  # 333856 Titanic 1997
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (333849, 6, 'Lior', 'I find the Titanic story itself interesting and emotional, although this older version is less engaging to me than the later adaptation.', null);  # 333849 Titanic 1915
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (337166, 10, 'Lior', 'I love Toy Story because it is warm, imaginative, funny, and emotionally meaningful for both children and adults.', null);  # 337166 Toy Story 1995
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (340652, 4, 'Lior', 'The historical setting is interesting, but because the film is centered on war and action, it is not really my kind of movie.', null);  # 340652 Troy 2004
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (644, 9, 'Lior', 'I really liked the enemies-to-lovers dynamic between Kat and Patrick, and the high school setting with witty dialogue makes it fun and memorable.', null);  # 10 Things I Hate About You 1999
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (849, 9, 'Lior', 'I enjoy family animations like this, especially the cute puppies and the light adventure story set in London.', null);  # 101 Dalmatians II: Patch's London Adventure 2003
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (850, 8, 'Lior', 'The songs and familiar characters make it fun and nostalgic, especially as a light family movie.', null);  # 101 Dalmatians Sing Along 1996
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (837, 7, 'Lior', 'I like the fairy-tale structure and imaginative setting, which makes it enjoyable.', null);  # 1001 Nights 1998
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (359297, 6, 'Lior', 'The story of a family trying to survive during an alien invasion is interesting, but the focus on action and tension makes it less engaging for me.', null);  # War of the Worlds 2005
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (360667, 7, 'Lior', 'The wedding theme and relationship focus make it more appealing, and I enjoy stories built around love and commitment.', null);  # Wedding Advice: Speak Now or Forever Hold Your Peace 2002
insert into personal_movies_ranking(movie_id, recommendation, suggested_by, justification, comment) values (366967, 7, 'Lior', 'A beautiful relationship-focused story that explores emotional connection and loss.', null);  # Without You 1999
